#include <EEPROM.h>
#include <avr/wdt.h>
extern uint8_t fsm_transition(uint8_t,uint8_t,uint8_t);
uint8_t state=0;
uint16_t crc16(uint8_t* d,uint8_t n){
  uint16_t c=0xFFFF;
  for(uint8_t i=0;i<n;i++){c^=(uint16_t)d[i]<<8;for(uint8_t j=0;j<8;j++)c=(c&0x8000)?(c<<1)^0x1021:(c<<1);}
  return c;}
float voter_read(){
  float v[3];
  for(int i=0;i<3;i++)v[i]=analogRead(A0+i)*5.0f/1023.0f;
  if(v[0]>v[1]){float t=v[0];v[0]=v[1];v[1]=t;}
  if(v[1]>v[2]){float t=v[1];v[1]=v[2];v[2]=t;}
  if(v[0]>v[1]){float t=v[0];v[0]=v[1];v[1]=t;}
  float m=v[1];
  for(int i=0;i<3;i++)if(m>0&&fabsf(v[i]-m)/m>0.1f)return -999.0f;
  return m;}
void led_update(uint8_t s){
  const uint8_t c[][3]={{0,255,0},{255,255,0},{255,0,0},{0,0,255}};
  if(s>3)s=3;
  analogWrite(9,c[s][0]);analogWrite(10,c[s][1]);analogWrite(11,c[s][2]);}
static uint8_t cerr=0;
static unsigned long rt=0;
void cmd_check(){
  if(Serial.available()>3){
    uint8_t buf[8];
    int n=Serial.readBytesUntil('\n',(char*)buf,8);
    if(n<2)return;
    uint16_t cc=crc16(buf,n-2);
    uint16_t mc=((uint16_t)buf[n-2]<<8)|buf[n-1];
    if(cc!=mc){cerr++;if(cerr>=3){state=fsm_transition(state,1,0xCC);cerr=0;}}
    else{cerr=0;state=fsm_transition(state,buf[0],buf[1]);}}}
void setup(){
  Serial.begin(115200);
  for(int p:{9,10,11})pinMode(p,OUTPUT);
  wdt_enable(WDTO_1S);
  if(MCUSR&(1<<WDRF)){Serial.println("WDT_RESET");MCUSR=0;}}
void loop(){
  wdt_reset();
  float v=voter_read();
  if(v<-100.0f&&state==0)state=fsm_transition(state,1,0xAA);
  if(state==1)state=fsm_transition(state,2,0);
  if(state==2&&(millis()-rt>3000)){rt=millis();state=fsm_transition(state,3,0);}
  if(state==3)state=fsm_transition(state,0,0);
  cmd_check();led_update(state);
  Serial.print("S:");Serial.println(state);
  delay(100);}
